#include <stdio.h>
#include <string.h>
#define MOD 1000000007

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        char s[5005]; scanf("%s", s);
        int maxL = 0;
        for(int d=1; d<N; ++d){
            int cur = 0;
            for(int i=0; i+d<N; ++i){
                if(s[i]!=s[i+d]){
                    ++cur;
                    if(cur> d) cur = d; // length cannot exceed distance
                    if(cur>maxL) maxL = cur;
                }else{
                    cur = 0;
                }
            }
        }
        long long pow2 = 1;
        for(int i=0;i<maxL;++i) pow2 = (pow2*2)%MOD;
        long long ans = (pow2 + MOD - 1)%MOD;
        printf("%lld\n", ans);
    }
    return 0;
}

