import sys
MOD = 1_000_000_007

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        s = next(it).strip()
        maxL = 0
        for d in range(1, N):
            cur = 0
            for i in range(N - d):
                if s[i] != s[i + d]:
                    cur += 1
                    if cur > d:
                        cur = d
                    if cur > maxL:
                        maxL = cur
                else:
                    cur = 0
        pow2 = pow(2, maxL, MOD)
        ans = (pow2 - 1) % MOD
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

