const fs = require('fs');
const MOD = 1000000007n;
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let results = [];
for (let t = 0; t < T; ++t) {
  const N = Number(input[idx++]);
  const s = input[idx++];
  let maxL = 0;
  for (let d = 1; d < N; ++d) {
    let cur = 0;
    for (let i = 0; i + d < N; ++i) {
      if (s[i] !== s[i + d]) {
        ++cur;
        if (cur > d) cur = d;
        if (cur > maxL) maxL = cur;
      } else {
        cur = 0;
      }
    }
  }
  // compute (2^maxL - 1) mod MOD using fast exponentiation with BigInt
  let pow = 1n;
  let base = 2n;
  let exp = BigInt(maxL);
  while (exp > 0n) {
    if (exp & 1n) pow = (pow * base) % MOD;
    base = (base * base) % MOD;
    exp >>= 1n;
  }
  const ans = (pow + MOD - 1n) % MOD;
  results.push(ans.toString());
}
